// C3: Physical sensing components
instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Motor current sensor measuring input current I_M of the first axis motor"
    DTDFVocab:producedData MotorCurrentDataTransmitted
]

instance MotorPositionEncoderSensor : DTDFVocab:SensingComponent [
    base:desc "Motor‑mounted position encoder providing motor angle r_M"
    DTDFVocab:producedData MotorPositionEncoderDataTransmitted
]

instance GearboxSecondaryEncoderSensor : DTDFVocab:SensingComponent [
    base:desc "Secondary encoder located behind the gearbox providing gearbox angle r_G and output angle r_out"
    DTDFVocab:producedData GearboxSecondaryEncoderDataTransmitted
]

// C4: Physical-to-virtual interaction (DataTransmitted)
instance MotorCurrentDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

instance MotorPositionEncoderDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorPositionEncoderSensor
]

instance GearboxSecondaryEncoderDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxSecondaryEncoderSensor
]

// C10: Data
instance CurrentTimeSeriesData : DTDFVocab:Data [
    base:desc "Time‑series of input current I_M streamed from MotorCurrentSensor"
    DTDFVocab:fromData MotorCurrentDataTransmitted
    DTDFVocab:inputTo MQTTBrokerEnabler, SimulinkExecutionEnabler
]

instance TorqueTimeSeriesData : DTDFVocab:Data [
    base:desc "Derived torque τ time‑series calculated from current and motor angle"
    DTDFVocab:fromData MotorCurrentDataTransmitted, MotorPositionEncoderDataTransmitted
    DTDFVocab:inputTo MQTTBrokerEnabler, SimulinkExecutionEnabler
]

instance AngularVelocityTimeSeriesData : DTDFVocab:Data [
    base:desc "Derived angular velocity ω time‑series calculated from encoder signals"
    DTDFVocab:fromData MotorPositionEncoderDataTransmitted, GearboxSecondaryEncoderDataTransmitted
    DTDFVocab:inputTo MQTTBrokerEnabler, SimulinkExecutionEnabler
]

instance FrictionEstimatesData : DTDFVocab:Data [
    base:desc "Real‑time friction estimates (static, kinetic, viscous coefficients) produced by identification models"
    DTDFVocab:fromData MotorCurrentDataTransmitted, MotorPositionEncoderDataTransmitted, GearboxSecondaryEncoderDataTransmitted
    DTDFVocab:inputTo MQTTBrokerEnabler, SimulinkExecutionEnabler, DashboardVisualizationEnabler
]

// C10: Models
instance SysMLMotorGearboxBlockModel : DTDFVocab:Model [
    base:desc "SysML Block Definition Diagram describing motor, gearbox and cycloidal transmission"
