]

instance SysMLMotorGearboxIBDModel : DTDFVocab:Model [
    base:desc "SysML Internal Block Diagram detailing connections of motor, gearboxes and sensors"
    DTDFVocab:inputTo SysMLModelRepositoryEnabler
]

instance SimulinkFrictionlessModel : DTDFVocab:Model [
    base:desc "MATLAB/Simulink model of frictionless behavior for the first axis"
    DTDFVocab:inputTo SimulinkExecutionEnabler
]

instance SimulinkCoulombViscousModel : DTDFVocab:Model [
    base:desc "Simulink white‑box model implementing Coulomb‑Viscous friction"
    DTDFVocab:inputTo SimulinkExecutionEnabler
]

instance SimulinkStribeckModel : DTDFVocab:Model [
    base:desc "Simulink black‑box model implementing Stribeck friction characteristic"
    DTDFVocab:inputTo SimulinkExecutionEnabler
]

instance SimulinkDahlModel : DTDFVocab:Model [
    base:desc "Simulink model of Dahl friction for dynamic stick‑slip behavior"
    DTDFVocab:inputTo SimulinkExecutionEnabler
]

instance SimulinkLuGreModel : DTDFVocab:Model [
    base:desc "Simulink implementation of LuGre friction model"
    DTDFVocab:inputTo SimulinkExecutionEnabler
]

instance FrictionIdentificationModel : DTDFVocab:Model [
    base:desc "Data‑driven identification model that extracts static, kinetic and viscous friction coefficients from current, torque and velocity data"
    DTDFVocab:inputTo SimulinkExecutionEnabler, AssetAdministrationShellEnabler
]

// C11: Enablers
instance MQTTBrokerEnabler : DTDFVocab:Enabler [
    base:desc "MQTT broker used for live streaming of sensor data (current, angle) from the robot to the digital twin"
    DTDFVocab:enables RealTimeFrictionIdentificationService, DashboardVisualizationService
]

instance SimulinkExecutionEnabler : DTDFVocab:Enabler [
    base:desc "MATLAB Simulink execution environment for running engineering and friction models"
    DTDFVocab:enables RealTimeFrictionIdentificationService, FrictionParameterUpdateService
]

instance SysMLModelRepositoryEnabler : DTDFVocab:Enabler [
    base:desc "Repository for storing and retrieving SysML engineering models"
    DTDFVocab:enables DashboardVisualizationService
]

instance AssetAdministrationShellEnabler : DTDFVocab:Enabler [
    base:desc "Asset Administration Shell (AAS) providing model integration and communication with the robot control system"
    DTDFVocab:enables FrictionParameterUpdateService
]

instance DashboardVisualizationEnabler : DTDFVocab:Enabler [
    base:desc "Custom dashboard used for visualizing measured and simulated data and interacting with the digital twin"
    DTDFVocab:enables DashboardVisualizationService
]

// C6: Services
instance RealTimeFrictionIdentificationService : DTDFVocab:Service [
    base:desc "Continuously identifies static, kinetic and viscous friction coefficients from live data"
    DTDFVocab:provides FrictionCoefficientsInsight
]

instance DashboardVisualizationService : DTDFVocab:Service [
    base:desc "Provides a visual dashboard for real‑time display of measured, simulated and identified friction data"
    DTDFVocab:provides VisualizedFrictionDataInsight
]

instance FrictionParameterUpdateService : DTDFVocab:Service [
    base:desc "Generates updated friction model parameters and pushes them to the robot control system to improve motion accuracy"
    DTDFVocab:provides UpdateRobotControlParametersAction
]

// C17: Insights/Actions
instance FrictionCoefficientsInsight : DTDFVocab:Insight [
    base:desc "Derived static, kinetic and viscous friction coefficients for the gearbox"
